                return;
            }
            
            console.log('[디버그] 4사분면 차트 데이터 검증 완료');
            console.log('[디버그] 필터 타입:', filterType);
            console.log('[디버그] 역량 개수:', chartLabels.length);
            
            const labels = chartLabels || [];
            
            // 기준값(원데이터)
            const basePoints = labels.map((name,i)=>({
                name,
                x: Number(chart_self[i] || 0),
                y: Number(chart_other[i] || 0)
            }));
            
            // 역량 → 역량군 매핑 및 팔레트(Executing, Influencing, Relationship, Strategic 순)
            const compToGroup = {};
            try {
                (groupToComps || []).forEach((compList, gi) => {
                    (compList || []).forEach(c => { compToGroup[c] = gi; });
                });
            } catch(_) {}
            const groupNameOf = (name)=>{
                const gi = compToGroup[name];
                return (gi != null && (groupLabels||[])[gi]) ? groupLabels[gi] : '기타';
            };
            const groupPalette = [
                'rgba(239,68,68,0.85)',   // Executing
                'rgba(59,130,246,0.85)',  // Influencing
                'rgba(139,92,246,0.85)',  // Relationship Building
                'rgba(34,197,94,0.85)'    // Strategic Adaptation
            ];
            const colorOf = (name)=>{
                const gi = compToGroup[name];
                return groupPalette[gi] || 'rgba(59,130,246,0.85)';
            };
            
            // 안정적 지터 생성기 (라벨 기반, 재로딩 시 동일)
            const hashFloat = (s) => {
                let h = 0;
                for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) | 0;
                return (h & 0xffff) / 0xffff; // [0,1)
            };
            const jitter = (name, axis, magnitude) => (hashFloat(`${name}-${axis}`) - 0.5) * 2 * magnitude;
            const JITTER_MAG = 0.755; // STEN 스케일에 맞춘 지터 (±0.592, 추가 30% 증가)
            
            // STEN 점수 변환 함수 (실제 데이터 분포 기반)
            const toSten = (score, competencyIndex) => {
                if (score === null || score === undefined || isNaN(score)) return null;
                
                // 해당 역량의 모집단 통계 가져오기
                const mean = competencyMeans[competencyIndex];
                const std = competencyStds[competencyIndex];
                
                if (std === 0) return 5.5; // 표준편차가 0인 경우
                
                // z-score 계산
                const zScore = (score - mean) / std;
                
                // STEN 변환 (평균 5.5, 표준편차 2)
                const sten = 5.5 + (zScore * 2);
                
                // 1-10 범위로 제한
                return Math.max(1, Math.min(10, sten));
            };
            
            // STEN 점수로 변환 (역량별 개별 통계 사용)
            const basePointsSten = chartLabels.map((name,i)=>({
                name,
                x: toSten(chart_self[i] || 0, i),      // 본인평가 → STEN
                y: toSten(chart_other[i] || 0, i),     // 타인평가 → STEN
                originalX: Number(chart_self[i] || 0),  // 원점수 보관
                originalY: Number(chart_other[i] || 0)  // 원점수 보관
            }));
            

            
            // 데이터 무결성 검증
            const validPoints = basePointsSten.filter(p => 
                p.x !== null && p.y !== null && 
                !isNaN(p.x) && !isNaN(p.y) &&
                p.name && p.name.trim() !== ''
            );
            
            if (validPoints.length === 0) {
                console.error('[오류] 유효한 STEN 데이터가 없습니다');
                quadEl.innerHTML = '<div style="text-align:center; padding:50px; color:#666;">유효한 차트 데이터가 없습니다.<br>데이터를 확인해주세요.</div>';
                return;
            }
            
            if (validPoints.length !== basePointsSten.length) {
                console.warn(`[경고] ${basePointsSten.length - validPoints.length}개 무효 데이터 제외됨`);
            }
            
            console.log('[디버그] STEN 변환 완료:', validPoints.length, '개 유효 역량');
            
            // 유효한 데이터만 사용
            const finalBasePoints = validPoints;
            
            // 필터링 적용 (유효한 데이터만 사용)
            let filteredPoints = finalBasePoints;
            if (filterType !== 'all') {
                const filterGroupIndex = ['executing', 'influencing', 'relationship', 'strategic'].indexOf(filterType);
                if (filterGroupIndex !== -1) {
                    filteredPoints = finalBasePoints.filter(p => compToGroup[p.name] === filterGroupIndex);
                    console.log('[디버그] 필터링 적용:', filterType, '→', filteredPoints.length, '개 역량');
                }
            }
            
            // 필터링 후에도 데이터가 있는지 확인
            if (!filteredPoints || filteredPoints.length === 0) {
                console.warn('[경고] 필터링 후 데이터가 없습니다');
                quadEl.innerHTML = '<div style="text-align:center; padding:50px; color:#666;">선택한 필터에 해당하는 데이터가 없습니다.</div>';
                return;
            }
            
            // STEN 중앙값 5.5로 고정 (모든 개인 리포트에서 동일한 기준선)
            const x0 = 5.5; // STEN 본인평가 중앙값
            const y0 = 5.5; // STEN 타인평가 중앙값
            
            // STEN 범위 사용 (0.5-10)
            const STEN_RANGE = [0.5, 10]; // STEN 0.5-10점 범위로 극단값 가시성 향상
            const xRange = STEN_RANGE;
            const yRange = STEN_RANGE;
            
            // 개인 데이터의 실제 범위 확인 (아웃라이어 감지용)
            const ext = (arr)=>{
                const vals = arr.filter(v=>!isNaN(v) && v !== null);
                return vals.length > 0 ? {min: Math.min(...vals), max: Math.max(...vals)} : {min: 1, max: 10};
            };
            const xExt = ext(basePointsSten.map(p=>p.x));
            const yExt = ext(basePointsSten.map(p=>p.y));
            
            // 아웃라이어 감지 및 클램핑
            const clamp = (v, [min,max]) => Math.max(min, Math.min(max, v));
            const isOutlier = (value, range) => value < range[0] || value > range[1];

            // 지터 적용 좌표 및 아웃라이어 분류
            const normalPoints = [];
            const outlierPoints = [];
            
            filteredPoints.forEach(p => {
                const originalX = p.x;
                const originalY = p.y;
                const jitteredX = originalX + jitter(p.name,'x',JITTER_MAG);
                const jitteredY = originalY + jitter(p.name,'y',JITTER_MAG);
                const clampedX = clamp(jitteredX, xRange);
                const clampedY = clamp(jitteredY, yRange);
                
                const pointData = {
                    name: p.name,
                    x: clampedX,
                    y: clampedY,
                    originalX: originalX,
                    originalY: originalY,
                    isXOutlier: isOutlier(originalX, xRange),
                    isYOutlier: isOutlier(originalY, yRange)
                };
                
                if (pointData.isXOutlier || pointData.isYOutlier) {
                    outlierPoints.push(pointData);
                } else {
                    normalPoints.push(pointData);
                }
            });
            
            // 일반 점들의 색상
            const normalColors = normalPoints.map(p => colorOf(p.name));
            // 아웃라이어 점들의 색상 (더 진하게)
            const outlierColors = outlierPoints.map(p => 'rgba(255,165,0,0.9)'); // 주황색으로 강조

            // 일반 점들 trace
            const normalTrace = {
                type: 'scatter',
                mode: 'markers+text',
                x: normalPoints.map(p=>p.x),
                y: normalPoints.map(p=>p.y),
                text: normalPoints.map(p=>p.name),
