                },
                customdata: outlierPoints.map(p => [p.originalX, p.originalY, groupNameOf(p.name), p.isXOutlier ? 'X축 범위 초과' : '', p.isYOutlier ? 'Y축 범위 초과' : '', p.x, p.y]),
                hovertemplate: '%{text}<br>%{customdata[2]}<br>STEN 변환점수: 본인 %{customdata[5]:.1f} / 타인 %{customdata[6]:.1f}<br><b style="color:orange;">🔸 아웃라이어</b><br>%{customdata[3]} %{customdata[4]}<extra></extra>',
                name: '아웃라이어',
