    function getPointColor(competencyName) {
        // 간단한 색상 매핑 (역량군별)
        const executingComps = ['추진력', '결단력', '원칙 중시', '자기 성찰', '성과/역량에 따른 엄정한 인사'];
        const influencingComps = ['고객 가치 최우선', '커뮤니케이션', '높은 목표 도전', '인재 확보 열의'];
        const relationshipComps = ['협업과 팀웍', '모티베이션', '타인 존중', '인재의 지속 성장 관심'];
        const strategicComps = ['통찰력', '전략적 사고/행동', '트렌드 센싱', '지속 학습'];
        
        if (executingComps.includes(competencyName)) return 'rgba(239,68,68,0.85)';
        if (influencingComps.includes(competencyName)) return 'rgba(59,130,246,0.85)';
        if (relationshipComps.includes(competencyName)) return 'rgba(139,92,246,0.85)';
        if (strategicComps.includes(competencyName)) return 'rgba(34,197,94,0.85)';
        return 'rgba(107,114,128,0.85)'; // 기본 색상
    }

