    function renderTraditionalRadar() {
        // 기존 레이더 차트 로직 유지
        let rMember = (groupStenMember || []).map(v => v === null ? null : Number(v));
        const theta = groupLabels || [];
        if (!theta.length) return;
        const thetaClosed = [...theta, theta[0]];
        const rMemberClosed = rMember && rMember.length ? [...rMember, rMember[0]] : rMember;
        const textMember = (rMemberClosed || []).map((v, i, arr) => i === arr.length - 1 ? '' : (v != null ? v.toFixed(1) : ''));

        // 배경 밴드 및 기준선
        let extraTraces = [];
        if (ENABLE_ENHANCED_EIRS) {
            const bands = [
                {r: 3, color: 'rgba(239,68,68,0.06)'},
                {r: 6, color: 'rgba(107,114,128,0.06)'},
                {r: 10, color: 'rgba(34,197,94,0.06)'}
            ].map(b => ({
                type: 'scatterpolar', r: new Array(thetaClosed.length).fill(b.r), theta: thetaClosed,
                fill: 'toself', mode: 'lines', line: {width: 0}, fillcolor: b.color, hoverinfo: 'skip', showlegend: false
            }));
            const orgBaseline = 5.5;
            const orgTrace = { type: 'scatterpolar', r: new Array(thetaClosed.length).fill(orgBaseline), theta: thetaClosed, mode: 'lines', line: {color: 'rgba(156,163,175,0.85)', width: 1.5, dash: 'dot'}, name: '조직평균 기준선 (STEN 5.5)', fill: 'none' };
            extraTraces = [...bands, orgTrace];
        }

        const memberTrace = {
            type: 'scatterpolar', r: rMemberClosed, theta: thetaClosed, fill: 'toself', name: '타인평가(STEN)',
            mode: 'lines+text',
            text: textMember,
            textposition: 'top center', textfont: { size: 10, color: 'rgba(55,65,81,0.8)' },
            line: { color: 'rgba(34,197,94,1)' }, fillcolor: 'rgba(34,197,94,0.2)'
        };

        // 개인 강점 유형 마커
        const top2Code = computeTop2Areas(rMember);
        const top2MarkerR = new Array(theta.length).fill(null);
        if (top2Code) {
            const top2AreaKeys = top2Code.split('');
            top2AreaKeys.forEach(key => {
                const index = AREA_KEYS.indexOf(key);
                if (index !== -1 && rMember[index] != null) {
                    top2MarkerR[index] = rMember[index];
                }
            });
        }
        const top2MarkerRClosed = [...top2MarkerR, top2MarkerR[0]];

        const top2MarkerTrace = {
            type: 'scatterpolar',
            r: top2MarkerRClosed,
            theta: thetaClosed,
            mode: 'markers',
            marker: { size: 12, color: 'rgb(255,193,7)', line: { width: 1, color: 'white' } },
            name: '개인 강점유형',
            showlegend: false,
            hoverinfo: 'skip'
        };

        const layout = { polar: { radialaxis: { range: [1, 10], tickfont: { size: 10 }, dtick: 2, gridcolor: 'rgba(0,0,0,0.06)' } }, legend: { orientation: 'h' }, margin: { t: 20, b: 20, l: 20, r: 20 } };
        Plotly.newPlot('groupRadarChart', [...extraTraces, top2MarkerTrace, memberTrace], layout, {displayModeBar: false});

        // 개인 유형 산정 및 표시
        try {
            const top2 = computeTop2Areas(rMember);
            renderStyleResult(top2);
        } catch (e) { console.warn('유형 산정 실패:', e); }
    }

