    const AREA_KEYS = ['E','I','R','S'];
    // groupLabels 순서가 Executing/Influencing/Relationship/Strategic 라는 전제
    function computeTop2Areas(stenArray) {
        const pairs = (stenArray || []).map((v,i)=>({ key: AREA_KEYS[i], val: (v==null? null : Number(v)) }));
        const valid = pairs.filter(p=>p.val!=null && !isNaN(p.val));
        if (valid.length < 2) return null;
        const priority = { 'E':0, 'I':1, 'R':2, 'S':3 }; // 동점 우선순위
        valid.sort((a,b)=> (b.val - a.val) || (priority[a.key] - priority[b.key]));
        const top1 = valid[0].key, top2 = valid[1].key;
        return top1 + top2; // 예: 'EI'
    }

