    function downloadPDF() {
        // 로딩 표시
        const btn = document.querySelector('.pdf-download-btn');
        const originalText = btn.innerHTML;
        btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> PDF 생성 중...';
        btn.disabled = true;
        
        // 차트가 완전히 렌더링될 때까지 대기
        setTimeout(() => {
            try {
                const element = document.querySelector('.main-content');
                const filename = `리더십평가리포트_${name}_2025.pdf`;
                
                const opt = {
                    margin: [10, 10, 10, 10],
                    filename: filename,
                    image: { type: 'jpeg', quality: 0.98 },
                    html2canvas: { 
                        scale: 1.5,
                        useCORS: true,
                        allowTaint: true,
                        backgroundColor: '#ffffff',
                        scrollY: 0,
                        width: 1200,
                        height: document.body.scrollHeight,
                        logging: false
                    },
                    jsPDF: { 
                        unit: 'mm', 
                        format: 'a4', 
                        orientation: 'portrait',
                        compress: true
                    }
                };

                // PDF 생성 시작
                html2pdf().set(opt).from(element).save().then(() => {
                    console.log('PDF 다운로드 완료');
                }).catch(err => {
                    console.error('PDF 생성 중 오류:', err);
                    alert('PDF 생성 중 오류가 발생했습니다. 다시 시도해주세요.');
                }).finally(() => {
                    // 버튼 상태 복원
                    btn.innerHTML = originalText;
                    btn.disabled = false;
                });
            } catch (error) {
                console.error('PDF 생성 초기화 오류:', error);
                alert('PDF 생성 중 오류가 발생했습니다. 다시 시도해주세요.');
                btn.innerHTML = originalText;
                btn.disabled = false;
            }
        }, 1500);
    }

