    // =========================
    // 조직 리더십 박스 스타일링
    // =========================
    function updateOrgLeadershipBoxes() {
        for (let i = 0; i < chartLabels.length; i++) {
            const competency = chartLabels[i];
            const score2024 = orgAvg2024[i];
            const score2025 = orgAvg2025[i];
            
            if (score2024 !== null && score2025 !== null) {
                const change = score2025 - score2024;
                const boxElement = document.getElementById(`box-${competency}`);
                const scoreElement = document.getElementById(`score-${competency}`);
                
                if (boxElement && scoreElement) {
                    // 점수 차이만 표시 (화살표 포함)
                    let arrow = '';
                    let colorClass = '';
                    
                    if (change > 0) {
                        arrow = '▲';
                        colorClass = 'bg-green-50';
                        scoreElement.className = 'text-sm mt-2 text-green-600 font-semibold';
                    } else if (change < 0) {
                        arrow = '▼';
                        colorClass = 'bg-pink-50';
                        scoreElement.className = 'text-sm mt-2 text-red-600 font-semibold';
                    } else {
                        arrow = '→';
                        colorClass = 'bg-gray-50';
                        scoreElement.className = 'text-sm mt-2 text-gray-600 font-semibold';
                    }
                    
                    // 박스 배경색 변경
                    boxElement.className = `text-center p-4 rounded-lg ${colorClass}`;
                    
                    // 점수 차이만 표시
                    scoreElement.innerHTML = `${arrow} ${change > 0 ? '+' : ''}${change.toFixed(1)}`;
                }
            }
        }
    }

