        // null/undefined 데이터 필터링 및 유효한 데이터만 추출
        const validData = labels.map((label, index) => ({
            label: label,
            value: data[index] || 0  // null/undefined인 경우 0으로 처리
        })).filter(item => item.value > 0);  // 0보다 큰 값만 유지
        
        // 내림차순 정렬
        validData.sort((a, b) => b.value - a.value);
        
        const sortedLabels = validData.map(item => item.label);
        const sortedData = validData.map(item => item.value);
        
        // 디버그: 정렬 후 데이터 출력
        console.log('[디버그] makeSortedBarChart - sortedLabels:', sortedLabels);
        console.log('[디버그] makeSortedBarChart - sortedData:', sortedData);
        
        new Chart(ctx, {
            type: 'bar',
            data: {
                labels: sortedLabels,
                datasets: [{ label: '점수', data: sortedData, backgroundColor: color }]
            },
            options: {
